import React, { useState } from 'react'
import { AiOutlineEye,AiOutlineEyeInvisible } from 'react-icons/ai';
import { toast } from 'react-hot-toast';
import { useNavigate } from 'react-router-dom';

const SignupForm = ({setIsLoggedIn}) => {

    const navigate=useNavigate();

    const [formData,setFormData]=useState({
        firstName:"",
        lastName:"",
        email:"",
        password:"",
        confirmPassword:"",

    })

    const [accountType,setAccountType]=useState("student");
    const [showPassword,setShowPassword]=useState(false);
    const [showConfirmPassword,setShowConfirmPassword]=useState(false);

    function changeHandler(event){

        setFormData((prevData)=>(
            {
                ...prevData,
                [event.target.name]:event.target.value
            }
        ))
    }

    function submitHandler(event){
        event.preventDefault();
        if(formData.password!=formData.confirmPassword)
        {
            toast.error("Passwords do not match");
            return;
        }

        setIsLoggedIn(true);
        toast.success("Account Created");
        const accountData={
            ...formData
        };

        const finalData={
            ...accountData,
            accountType
        }

        console.log("Printing  account data");
        console.log(accountData);
        navigate("/dashboard");
        
    }

  return (
    <div>

        

        {/* student instructor tab */}

        <div className='flex bg-richblack-800 p-1 gap-x-1 my-6 rounded-full max-w-max'>
            <button className={`${accountType==="student"?
            "bg-richblack-900 text-richblack-5 "
            :" bg-transparent text-richblack-200"} py-2 px-5 rounded-full transition-all duration-200`}
            onClick={()=>setAccountType("student")}>
                Student
            </button>

            <button className={`${accountType==="instructor"?
            "bg-richblack-900 text-richblack-5 "
            :" bg-transparent text-richblack-200"} py-2 px-5 rounded-full transition-all duration-200`}
            onClick={()=>setAccountType("instructor")}>
                Instructor
            </button>
        </div>
        
        <form onSubmit={submitHandler} className='flex flex-col w-full gap-y-4 mt-6'>
            {/* firstName LastName */}
            <div className='flex gap-x-4 mt-2'>
                <label className="w-full">
                    <p className='text-[0.875rem] text-richblack-5 mb-1 leading-[1.375rem]'>First Name <sup className='text-pink-200'>*</sup></p>
                    <input className='bg-richblack-800 rounded-[0.5rem] text-richblack-5 w-full p-[8px]'
                        required
                        type='text'
                        name="firstName"
                        onChange={changeHandler}
                        placeholder='Enter First Name'
                        value={formData.firstName}
                    />
                </label>
                
                <label className='w-full'>
                    <p className='text-[0.875rem] text-richblack-5 mb-1 leading-[1.375rem]'>Last Name <sup className='text-pink-200'>*</sup></p>
                    <input className='bg-richblack-800 rounded-[0.5rem] text-richblack-5 w-full p-[8px]'
                        required
                        type='text'
                        name="lastName"
                        onChange={changeHandler}
                        placeholder='Enter Last Name'
                        value={formData.lastName}
                    />
                </label>
            </div>

            {/* email */}
            <label className='w-full mt-2'>
                <p className='text-[0.875rem] text-richblack-5 mb-1 leading-[1.375rem]'>Email Address <sup className='text-pink-200'>*</sup></p>
                <input className='bg-richblack-800 rounded-[0.5rem] text-richblack-5 w-full p-[8px]'
                    required
                    type='email'
                    name='email'
                    value={formData.email}
                    onChange={changeHandler}
                    placeholder='Enter email address'
                />
            </label>

            {/* createPassword and confirm Password */}
            <div className='flex gap-x-4 mt-2'>
                <label className='relative w-full'>
                    <p className='text-[0.875rem] text-richblack-5 mb-1 leading-[1.375rem]'>Create Password <sup className='text-pink-200'>*</sup></p>
                    <input className='bg-richblack-800 rounded-[0.5rem] text-richblack-5 w-full p-[8px]'
                        required
                        type={showPassword?("text"):("password")}
                        name='password'
                        value={formData.password}
                        onChange={changeHandler}
                        placeholder='Enter password'
                        />

                        <span className='absolute right-3 top-[34px] cursor-pointer'
                        onClick={()=>{ setShowPassword((prev)=>!prev)} } >
                            {showPassword?(<AiOutlineEyeInvisible fontSize={24} fill='#AFB2BF' />):(<AiOutlineEye fontSize={24} fill='#AFB2BF' />)}
                        </span>
                </label>

                <label className=' relative w-full'>
                    <p className='text-[0.875rem] text-richblack-5 mb-1 leading-[1.375rem]'>Confirm Password <sup className='text-pink-200'>*</sup></p>
                    <input className='bg-richblack-800 rounded-[0.5rem] text-richblack-5 w-full p-[8px]'
                        required
                        type={showConfirmPassword?("text"):("password")}
                        name='confirmPassword'
                        value={formData.confirmPassword}
                        onChange={changeHandler}
                        placeholder='Confirm password'
                        />

                        <span className='absolute right-3 top-[34px] cursor-pointer'
                         onClick={()=>{ setShowConfirmPassword((prev)=>!prev)} } >
                            {showConfirmPassword?(<AiOutlineEyeInvisible fontSize={24} fill='#AFB2BF' />):(<AiOutlineEye fontSize={24} fill='#AFB2BF' />)}
                        </span>
                </label>
            </div>

            <button className='bg-yellow-50 rounded-[8px] font-medium text-richblack-900 px-[12px] py-[8px]'>Create Account</button>
        </form>

    </div>
  )
}

export default SignupForm
